using System;

namespace DoubleEntryAccounting
{
    class Program
    {
        static void Main(string[] args)
        {
            // Create accounts
            Account cash = new Account("Cash", AccountType.Asset);
            Account accountsReceivable = new Account("Accounts Receivable", AccountType.Asset);
            Account serviceRevenue = new Account("Service Revenue", AccountType.Revenue);
            Account salariesExpense = new Account("Salaries Expense", AccountType.Expense);

            // Record transactions
            cash.Debit(100);
            accountsReceivable.Credit(100);

            serviceRevenue.Credit(50);
            cash.Debit(50);

            salariesExpense.Debit(20);
            cash.Credit(20);

            // Print balances
