            Console.WriteLine("Accounts Receivable: " + accountsReceivable.Balance);
            Console.WriteLine("Service Revenue: " + serviceRevenue.Balance);
            Console.WriteLine("Salaries Expense: " + salariesExpense.Balance);
        }
    }

    // Account class
    public class Account
    {
        public string Name { get; set; }
        public AccountType Type { get; set; }
        public decimal Balance { get; set; }

        public Account(string name, AccountType type)
        {
            this.Name = name;
            this.Type = type;
            this.Balance = 0;
        }

        public void Credit(decimal amount)
        {
            this.Balance += amount;
        }

        public void Debit(decimal amount)
        {
            this.Balance -= amount;
        }
    }

    // Account type enum
    public enum AccountType
    {
        Asset,
        Liability,
        Revenue,
        Expense
    }
