            // Add a transaction: Debit Cash, Credit Service Revenue (Revenue)
            transaction.AddEntry(new TransactionEntry("Cash", 100, TransactionEntryType.Debit));
            transaction.AddEntry(new TransactionEntry("Service Revenue", 100, TransactionEntryType.Credit));

            // Add another transaction: Debit Salaries Expense, Credit Cash
            transaction.AddEntry(new TransactionEntry("Salaries Expense", 200, TransactionEntryType.Debit));
            transaction.AddEntry(new TransactionEntry("Cash", 200, TransactionEntryType.Credit));

            // Apply the transaction to the chart of accounts
            transaction.Apply(chart);

            // Print account balances
            Console.WriteLine("Account Balances:");
            foreach (var account in chart.Accounts)
            {
                Console.WriteLine($"{account.Name}: {account.Balance}");
            }
        }
