    public class Account
    {
        public string Name { get; set; }
        public AccountType Type { get; set; }
        public decimal Balance { get; set; }

        public Account(string name, AccountType type)
        {
            Name = name;
            Type = type;
            Balance = 0;
        }

        public void Debit(decimal amount)
        {
            Balance += amount;
        }

        public void Credit(decimal amount)
        {
            Balance -= amount;
        }
    }

    // Account type enum
    public enum AccountType
    {
        Asset,
        Liability,
        Revenue,
        Expense
    }

    // TransactionEntry class
    public class TransactionEntry
    {
        public string AccountName { get; set; }
        public decimal Amount { get; set; }
        public TransactionEntryType Type { get; set; }

        public TransactionEntry(string accountName, decimal amount, TransactionEntryType type)
        {
            AccountName = accountName;
            Amount = amount;
            Type = type;
        }
    }

    // TransactionEntryType enum
    public enum TransactionEntryType
    {
        Debit,
        Credit
    }

