            {
                var account = chart.FindAccount(entry.AccountName);
                if (account != null)
                {
                    if (entry.Type == TransactionEntryType.Debit)
                    {
                        account.Debit(entry.Amount);
                    }
                    else
                    {
                        account.Credit(entry.Amount);
                    }
