  contentType: file.mimetype ?? undefined,
  filename: file.originalFilename ?? undefined,
});
```
Keep in mind that using `readFileSync` can have performance implications if you're dealing with large files, as it can block the Node.js event loop. If you're working with large files, consider using a streaming approach instead.

To use a streaming approach for file upload, you can use the `formidable` package which allows you to parse incoming form data, including file uploads, and handle them in a streaming fashion.

Here's an example of how you can modify your code to use `formidable` for streaming file upload:
```javascript
import formidable from 'formidable';

export const apiRouteHandler = async (req, res) => {
  const form = formidable({
    multiples: false,
    uploadDir: './uploads', // specify the directory where uploaded files will be stored
    keepExtensions: true, // keep file extensions
  });

  form.parse(req, (err, fields, files) => {
