private static void addNewUserToProject(Project project) {
    // Create a new user
    User newUser = project.createUser("newUser", "New User", "newUser@example.com");

    // Optionally, set user roles
    newUser.setRoles(project.getRole("admin")); // Replace "admin" with the actual role name

    // Add the user to the project
    project.addUser(newUser);

    logger.info("User 'newUser' added to the project successfully.");
}
