contract CommunityTaxSmartContract {
    // Constants
    uint public constant MIN_BASIC_TAX_INDIVIDUAL = 5;
    uint public constant MIN_BASIC_TAX_CORPORATION = 500;
    uint public constant MAX_ADDITIONAL_INDIVIDUAL = 5000;
    uint public constant MAX_ADDITIONAL_CORPORATION = 10000;
    uint public constant ADDITIONAL_RATE_INDIVIDUAL = 1;
    uint public constant ADDITIONAL_RATE_CORPORATION = 2;
    uint public constant INTEREST_RATE = 1; // 1% per month

    // Tax period
    uint public taxDeadlineMonth = 2; // February
    uint public taxDeadlineYear = block.year;

    // Function to calculate individual tax
    function calculateIndividualTax(
        uint age,
        string memory employmentStatus,
        uint annualIncome,
        uint propertyValue,
        bool isExempt,
        bool isResident
    ) public view returns (uint) {
        if (isExempt || !isResident) {
            return 0;
        }

        uint basicTax = MIN_BASIC_TAX_INDIVIDUAL;
        uint additionalTax = 0;

        // Additional tax based on income
        if (employmentStatus == "employed" || employmentStatus == "self-employed" || employmentStatus == "owner") {
            uint incomeTaxBase = annualIncome;
            if (incomeTaxBase > 0) {
                additionalTax += (incomeTaxBase / 1000) * ADDITIONAL_RATE_INDIVIDUAL;
            }
        }

        // Additional tax based on property
        if (propertyValue > 0) {
            uint propertyTax = (propertyValue / 1000) * ADDITIONAL_RATE_INDIVIDUAL;
            additionalTax += propertyTax;
        }

        // Cap additional tax
        if (additionalTax > MAX_ADDITIONAL_INDIVIDUAL) {
            additionalTax = MAX_ADDITIONAL_INDIVIDUAL;
        }

        return basicTax + additionalTax;
    }

    // Function to calculate corporate tax
    function calculateCorporateTax(
        string memory type,
        uint grossReceipts,
        uint realEstateValue,
        bool isExempt,
        bool isResident
    ) public view returns (uint) {
        if (isExempt || !isResident) {
            return 0;
        }

        uint basicTax = MIN_BASIC_TAX_CORPORATION;
        uint additionalTax = 0;

        // Additional tax based on income
        if (grossReceipts > 0) {
            uint incomeTaxBase = grossReceipts;
            if (incomeTaxBase > 0) {
                additionalTax += (incomeTaxBase / 5000) * ADDITIONAL_RATE_CORPORATION;
            }
        }

        // Additional tax based on real estate
        if (realEstateValue > 0) {
            uint propertyTax = (realEstateValue / 5000) * ADDITIONAL_RATE_CORPORATION;
            additionalTax += propertyTax;
        }

        // Cap additional tax
        if (additionalTax > MAX_ADDITIONAL_CORPORATION) {
            additionalTax = MAX_ADDITIONAL_CORPORATION;
        }

        return basicTax + additionalTax;
    }

    // Function to calculate interest if tax is paid late
    function calculateInterest(uint taxAmount, uint daysLate) public view returns (uint) {
        return (taxAmount * daysLate / 30) * INTEREST_RATE;
    }

    // Function to check if tax is due
    function isTaxDue(uint paymentMonth, uint paymentYear) public view returns (bool) {
        return (paymentMonth == taxDeadlineMonth && paymentYear == taxDeadlineYear);
    }
}
